namespace optiling {

// UB budget for per-core (conservative share)
static constexpr uint32_t UB_BUDGET_BYTES = 192 * 1024;
// Align tiles to favor DMA bursts
static constexpr uint32_t ALIGN_ELEMS = 512;
// Hard cap for per-iteration output pixels
static constexpr uint32_t HARD_CAP_PIX = 16384;

static ge::graphStatus TilingFunc(gert::TilingContext *context)
{
    ConvStandard2dSquareInputAsymmetricKernelDilatedPaddedCustomTilingData tiling;

    // Shapes
    const gert::Shape *x_shape = context->GetInputShape(0); // [N, C_in, H, W]
    const gert::Shape *w_shape = context->GetInputShape(1); // [C_out, C_in, KH, KW]

    const uint32_t N   = static_cast<uint32_t>(x_shape->GetDim(0));
    const uint32_t CIn = static_cast<uint32_t>(x_shape->GetDim(1));
    const uint32_t H   = static_cast<uint32_t>(x_shape->GetDim(2));
    const uint32_t W   = static_cast<uint32_t>(x_shape->GetDim(3));

    const uint32_t COut = static_cast<uint32_t>(w_shape->GetDim(0));
    const uint32_t KH   = static_cast<uint32_t>(w_shape->GetDim(2));
    const uint32_t KW   = static_cast<uint32_t>(w_shape->GetDim(3));

    const gert::RuntimeAttrs *attrs = context->GetAttrs();
    const int32_t *strideH  = attrs->GetAttrPointer<int32_t>(0);
    const int32_t *strideW  = attrs->GetAttrPointer<int32_t>(1);
    const int32_t *padTop   = attrs->GetAttrPointer<int32_t>(2);
    const int32_t *padBottom= attrs->GetAttrPointer<int32_t>(3);
    const int32_t *padLeft  = attrs->GetAttrPointer<int32_t>(4);
    const int32_t *padRight = attrs->GetAttrPointer<int32_t>(5);
    const int32_t *dilH     = attrs->GetAttrPointer<int32_t>(6);
    const int32_t *dilW     = attrs->GetAttrPointer<int32_t>(7);
    // groups attr ignored (assumed 1)

    const uint32_t effKH = static_cast<uint32_t>((*dilH) * static_cast<int32_t>(KH - 1) + 1);
    const uint32_t effKW = static_cast<uint32_t>((*dilW) * static_cast<int32_t>(KW - 1) + 1);

    const uint32_t HOut = (H + static_cast<uint32_t>(*padTop + *padBottom) >= effKH)
                            ? static_cast<uint32_t>((static_cast<int64_t>(H) + *padTop + *padBottom - effKH) / *strideH + 1)
                            : 0U;
    const uint32_t WOut = (W + static_cast<uint32_t>(*padLeft + *padRight) >= effKW)
                            ? static_cast<uint32_t>((static_cast<int64_t>(W) + *padLeft + *padRight - effKW) / *strideW + 1)
                            : 0U;

    // Tile pixels based on UB budget minus weight slice
    const uint32_t weightSlice = CIn * KH * KW;               // elements for one output channel
    const uint32_t weightBytes = weightSlice * 4U;            // float32
    uint32_t usableBytes = (UB_BUDGET_BYTES > weightBytes) ? (UB_BUDGET_BYTES - weightBytes) : (32U * 1024U);
    uint32_t maxTilePix = usableBytes / 4U;                   // elements (floats)
    maxTilePix = AlignDown(maxTilePix, ALIGN_ELEMS);
    if (maxTilePix < ALIGN_ELEMS) maxTilePix = ALIGN_ELEMS;
    if (maxTilePix > HARD_CAP_PIX) maxTilePix = AlignDown(HARD_CAP_PIX, ALIGN_ELEMS);

    uint32_t tilePixels = maxTilePix;
    const uint64_t totalPixPerOCN = static_cast<uint64_t>(HOut) * static_cast<uint64_t>(WOut);
    if (totalPixPerOCN < tilePixels) {
        uint32_t aligned = AlignDown(static_cast<uint32_t>(totalPixPerOCN), ALIGN_ELEMS);
        tilePixels = (aligned > 0U) ? aligned : static_cast<uint32_t>(totalPixPerOCN);
    }

    // Block dim heuristic: distribute over N * COut
    const uint32_t combos = (N == 0U || COut == 0U) ? 1U : (N * COut);
    uint32_t blockDim = combos;
    if (blockDim < 8U) blockDim = 8U;
    if (blockDim > 24U) blockDim = 24U;
