    tiling.set_CIn(CIn);
    tiling.set_H(H);
    tiling.set_W(W);
    tiling.set_COut(COut);
    tiling.set_KH(KH);
    tiling.set_KW(KW);
    tiling.set_HOut(HOut);
    tiling.set_WOut(WOut);
    tiling.set_strideH(static_cast<uint32_t>(*strideH));
    tiling.set_strideW(static_cast<uint32_t>(*strideW));
    tiling.set_padTop(static_cast<uint32_t>(*padTop));
    tiling.set_padBottom(static_cast<uint32_t>(*padBottom));
    tiling.set_padLeft(static_cast<uint32_t>(*padLeft));
    tiling.set_padRight(static_cast<uint32_t>(*padRight));
    tiling.set_dilationH(static_cast<uint32_t>(*dilH));
    tiling.set_dilationW(static_cast<uint32_t>(*dilW));
    tiling.set_tilePixels(tilePixels);
    tiling.set_blockDim(blockDim);

    tiling.SaveToBuffer(context->GetRawTilingData()->GetData(),
                        context->GetRawTilingData()->GetCapacity());
    context->GetRawTilingData()->SetDataSize(tiling.GetDataSize());

    size_t *currentWorkspace = context->GetWorkspaceSizes(1);
    currentWorkspace[0] = 0;
    return ge::GRAPH_SUCCESS;
}

